selector {
    background: linear-gradient(135deg, #111111 0%, #000 100%);
    border: 1px solid rgba(255, 255, 255, 0.08);
    border-radius: 24px;

    gap: 0.5rem;
    align-items: center;
    overflow: hidden;
}

/* --- High-End Light Theme Features (Architectural Air Design) --- */

/* 1. Container Alignment */
selector .e-con-inner {
    display: flex !important;
    gap: 30px !important;
    justify-content: center;
    padding: 40px 0;
}

/* 2. The Card Background & Shape */
.featuress {
    background: #ffffff !important;
    padding: 50px 40px !important;
    border-radius: 16px !important; /* Elegant soft corners */
    border: 1px solid #f0f0f0 !important; /* Extremely delicate border */
    position: relative;
    overflow: hidden;
    display: flex;
    flex-direction: column;
    /* Ultra-soft default shadow */
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.02) !important;
    transition: all 0.5s cubic-bezier(0.25, 1, 0.5, 1) !important;
    z-index: 1;
}

/* 3. The "Bloom" Effect (A subtle, elegant corner glow on hover) */
.featuress::before {
    content: '';
    position: absolute;
    top: -50px;
    right: -50px;
    width: 200px;
    height: 200px;
    /* Soft red glow matching Lighting Boss branding */
    background: radial-gradient(circle, rgba(236, 28, 36, 0.04) 0%, transparent 70%); 
    border-radius: 50%;
    opacity: 0;
    transform: scale(0.5);
    transition: all 0.7s cubic-bezier(0.25, 1, 0.5, 1);
    z-index: -1;
    pointer-events: none;
}

/* 4. Hover State: Floating & Blooming */
.featuress:hover {
    transform: translateY(-8px);
    border-color: #ffffff !important;
    /* Shadow deepens gracefully */
    box-shadow: 0 20px 40px rgba(0, 0, 0, 0.08) !important; 
}

.featuress:hover::before {
    opacity: 1;
    transform: scale(1.5);
}


.featuress:hover .elementor-button::after {
    transform: translateX(6px);
}

/* Responsive Adjustments */
@media (max-width: 1024px) {
  selector  .e-con-inner { flex-wrap: wrap !important; gap: 20px !important; }
    .featuress { width: calc(50% - 10px) !important; }
}

@media (max-width: 767px) {
    .featuress { width: 100% !important; }
}

/* Parent container */
.category-products {
    padding: 0 !important;
    overflow: hidden !important;
    border: 1px solid rgba(255, 255, 255, 0.08) !important;
    border-radius: 8px !important;
    transition: all 0.3s ease !important;
}

/* Icon box wrapper - flex row, full height */
.icon-category .elementor-icon-box-wrapper {
    display: flex !important;
    flex-direction: row !important;
    align-items: stretch !important;
    gap: 0 !important;
    height: 100% !important;
}

/* Icon side - dark background */
.icon-category .elementor-icon-box-icon {
    background: #181818 !important;
    width: 80px !important;
    min-width: 80px !important;
    display: flex !important;
    align-items: center !important;
    justify-content: center !important;
    padding: 0 !important;
    margin: 0 !important;
    transition: all 0.3s ease !important;
    border-right: 1px solid transparent !important;
}

/* Icon color */
.icon-category .elementor-icon-box-icon i {
    color: white !important;
    transition: color 0.3s ease !important;
}

/* Content side - lighter background */
.icon-category .elementor-icon-box-content {
    background: #111111 !important;
    flex: 1 !important;
    display: flex !important;
    flex-direction: column !important;
    justify-content: center !important;
    padding: 20px !important;
}

/* Title */
.icon-category .elementor-icon-box-title {
    transition: color 0.3s ease !important;
}

/* ── HOVER ── */
.category-products:hover {
    border-color: rgba(236, 28, 36, 0.4) !important;
    box-shadow: -5px 5px 20px rgba(0, 0, 0, 0.5) !important;
    transform: translateX(8px) !important;
}

.category-products:hover .elementor-icon-box-icon {
    background: rgba(236, 28, 36, 0.1) !important;
    border-right-color: rgba(236, 28, 36, 0.2) !important;
}

.category-products:hover .elementor-icon-box-icon i {
    color: #EC1C24 !important;
}

.category-products:hover .elementor-icon-box-title span {
    color: #EC1C24 !important;
}




/* Final resting state defined here, not held by animation */
.category-products {
    opacity: 1;
    transition: transform 0.3s ease, border-color 0.3s ease, box-shadow 0.3s ease !important;
    animation: fadeSlideUp 0.5s ease backwards;
}

/* Stagger each column */
.category-products:nth-child(1) { animation-delay: 0.1s; }
.category-products:nth-child(2) { animation-delay: 0.2s; }
.category-products:nth-child(3) { animation-delay: 0.3s; }
.category-products:nth-child(4) { animation-delay: 0.4s; }
.category-products:nth-child(5) { animation-delay: 0.5s; }
.category-products:nth-child(6) { animation-delay: 0.6s; }

@keyframes fadeSlideUp {
    from {
        opacity: 0;
        transform: translateY(30px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

